class Solution:
    def findRedundantDirectedConnection(self, edges):
        n = len(edges)
        # brute force: try removing each edge from last to first; pick the last-indexed
        # removal that yields a valid rooted tree.
        def is_rooted_tree(es):
            nodes = set()
            for u, v in es:
                nodes.add(u)
                nodes.add(v)
            indeg = {}
            adj = {}
            for u, v in es:
                indeg[v] = indeg.get(v, 0) + 1
                adj.setdefault(u, []).append(v)
            roots = [x for x in nodes if indeg.get(x, 0) == 0]
            if len(roots) != 1:
                return False
            for x in nodes:
                if indeg.get(x, 0) > 1:
                    return False
            root = roots[0]
            seen = set()
            stack = [root]
            while stack:
                cur = stack.pop()
                if cur in seen:
                    return False
                seen.add(cur)
                for nxt in adj.get(cur, []):
                    stack.append(nxt)
            return len(seen) == len(nodes)
        for i in range(n - 1, -1, -1):
            rest = edges[:i] + edges[i + 1:]
            if is_rooted_tree(rest):
                return edges[i]
        return []

