class Solution:
    def findRedundantDirectedConnection(self, edges):
        n = len(edges)
        parent = [0] * (n + 1)
        cand1 = cand2 = None
        for i, (u, v) in enumerate(edges):
            if parent[v] != 0:
                cand1 = [parent[v], v]
                cand2 = [u, v]
            else:
                parent[v] = u
        uf = list(range(n + 1))
        def find(x):
            while uf[x] != x:
                uf[x] = uf[uf[x]]
                x = uf[x]
            return x
        for u, v in edges:
            if cand2 and [u, v] == cand2:
                continue
            ru, rv = find(u), find(v)
            if ru == rv:
                if cand1:
                    return cand1
                return [u, v]
            uf[rv] = ru
        return cand2

